    demoController?: DemoWorkspaceController;
    timer?: BridgeTimerDriver;
  }) {
    this.#preferences = options?.preferences ?? {
      async getBridgeBaseUrl() {
        return null;
      },
      async setBridgeBaseUrl() {},
      async getPairingUri() {
        return null;
      },
      async setPairingUri() {},
