              <Text className="text-xs text-muted-foreground">Refresh</Text>
            </Pressable>
          }
        />

        {machines.length > 0 ? (
          <View className="gap-2 pb-4">
            {machines.map((machine) => (
              <MachineItem
                key={machine.machineId}
                machine={machine}
